#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, w[105];
    set<int> ans;
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> w[i];
    }
    for (int i = 1; i < (1 << n); i++) {
        for (int as = 1; as < (1 << n); as++) {
            int sum_w = 0;
            for (int j = 0; j < n; j++) {
                int tmp = ((i & (1 << j)) >> j) * w[j];
                sum_w += (as & (1 << j) ? tmp : -tmp);
                // printf("%2d ", (as & (1 << j) ? tmp : -tmp));
                // printf("%d ", tmp);
                // printf("%d ", w[j]);
            }
            if (sum_w > 0) ans.insert(sum_w);
        }
    }
    cout << ans.size();
    return 0;
}
